"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[81102],{53261:e=>{e.exports=JSON.parse('{"tag":{"label":"care","permalink":"/docs/tags/care","allTagsPath":"/docs/tags","count":45,"items":[{"id":"Rats/getting-started/rat-nutrition-guide","title":"A Guide to Proper Rat Nutrition","description":"Proper nutrition is the cornerstone of your pet rat\'s health and longevity. As omnivores, rats have specific dietary needs that must be met to prevent obesity, nutritional deficiencies, and other...","permalink":"/docs/Rats/getting-started/rat-nutrition-guide"},{"id":"Rats/health-and-wellness/rat-introductions","title":"A Guide to Safe and Successful Rat Introductions","description":"Introducing a new rat to your existing group (or \'mischief\') is an exciting step, but it must be handled with care and patience. Rats are territorial and have complex social hierarchies. A proper...","permalink":"/docs/Rats/health-and-wellness/rat-introductions"},{"id":"Rabbits/getting-started/basic-care","title":"Basic Care for Pet Rabbits","description":"An essential guide to the fundamental aspects of pet rabbit care, including diet, housing, exercise, and social needs.","permalink":"/docs/Rabbits/getting-started/basic-care"},{"id":"Rats/getting-started/the-ideal-rat-habitat-guide","title":"Creating the Ideal Habitat for Your Pet Rats","description":"A well-designed habitat is crucial for the health, happiness, and safety of your pet rats. As active, intelligent, and social creatures, they need a space that supports their natural behaviors like...","permalink":"/docs/Rats/getting-started/the-ideal-rat-habitat-guide"},{"id":"Rats/illnesses-and-conditions/diabetes-in-rats","title":"Diabetes in Rats","description":"Diabetes Mellitus is a condition in which the body either fails to produce enough insulin or cannot use it effectively, resulting in persistently high blood sugar (hyperglycemia). While not common in pet rats, it does occur \u2014 particularly in older or overweight individuals \u2014 and requires prompt veterinary attention and a committed management plan. Understanding the signs, how diagnosis works, and what treatment looks like can make a significant difference for an affected rat 1.","permalink":"/docs/Rats/illnesses-and-conditions/diabetes-in-rats"},{"id":"guinea-pigs/getting-started/essential-supplies","title":"Essential Supplies for Guinea Pigs: A Helping All Little Things Guide","description":"Bringing home a guinea pig (or better yet\u2014a pair!) is an exciting and joyful experience. To set your new friends up for a happy, healthy life, it\u2019s important to have the right supplies ready from day...","permalink":"/docs/guinea-pigs/getting-started/essential-supplies"},{"id":"Rabbits/getting-started/essential-supplies-for-rabbits","title":"Essential Supplies for Your Rabbit Companion","description":"Bringing a rabbit into your home is a long-term commitment, and providing the right supplies is the first step to ensuring a happy, healthy life for your new friend. Rabbits have specific needs that...","permalink":"/docs/Rabbits/getting-started/essential-supplies-for-rabbits"},{"id":"guinea-pigs/getting-started/grooming-your-guinea-pig","title":"Grooming Your Guinea Pig","description":"Grooming is an essential part of responsible guinea pig care that goes beyond just keeping them looking their best. Regular grooming sessions are an excellent opportunity to bond with your pet and...","permalink":"/docs/guinea-pigs/getting-started/grooming-your-guinea-pig"},{"id":"Chinchillas/getting-started/grooming-your-chinchilla","title":"Grooming Your Pet Chinchilla","description":"A guide to the unique grooming needs of chinchillas, focusing on the importance of dust baths and how to provide them safely.","permalink":"/docs/Chinchillas/getting-started/grooming-your-chinchilla"},{"id":"Degus/getting-started/grooming-your-degu","title":"Grooming Your Pet Degu","description":"A guide to the grooming needs of pet degus, with a focus on the essential role of dust baths for maintaining their coat and skin health.","permalink":"/docs/Degus/getting-started/grooming-your-degu"},{"id":"Ferrets/getting-started/grooming-your-ferret","title":"Grooming Your Pet Ferret","description":"A guide to the essential grooming practices for pet ferrets, including nail trimming, ear cleaning, and bathing.","permalink":"/docs/Ferrets/getting-started/grooming-your-ferret"},{"id":"Gerbils/getting-started/grooming-your-gerbil","title":"Grooming Your Pet Gerbil","description":"A guide to the minimal grooming needs of pet gerbils, including the role of sand baths, brushing, and nail care.","permalink":"/docs/Gerbils/getting-started/grooming-your-gerbil"},{"id":"Hamsters/getting-started/grooming-your-hamster","title":"Grooming Your Pet Hamster","description":"A guide to hamster grooming, focusing on their natural self-cleaning abilities and providing instructions for sand baths and occasional assistance.","permalink":"/docs/Hamsters/getting-started/grooming-your-hamster"},{"id":"Hedgehogs/getting-started/grooming-your-hedgehog","title":"Grooming Your Pet Hedgehog","description":"A guide to the essential grooming needs of a pet hedgehog, including how to give them a bath and trim their nails safely.","permalink":"/docs/Hedgehogs/getting-started/grooming-your-hedgehog"},{"id":"Rabbits/getting-started/grooming-your-rabbit","title":"Grooming Your Pet Rabbit","description":"A guide to the essential grooming needs of a pet rabbit, including brushing, nail trimming, and cleaning scent glands.","permalink":"/docs/Rabbits/getting-started/grooming-your-rabbit"},{"id":"Rats/getting-started/grooming-your-rat","title":"Grooming Your Rat","description":"Learn the best practices for rat grooming, including when and how to bathe them, how to trim their nails, and how to encourage their natural self-grooming habits.","permalink":"/docs/Rats/getting-started/grooming-your-rat"},{"id":"guinea-pigs/getting-started/guineapigcare","title":"Guinea Pig Care","description":"Plain, quality pellets are best for guinea pigs. Guinea pigs under 6 months old should be fed an Alfalfa pellet and hay-based diet. Do not feed your guinea pig any food with artificial coloring,...","permalink":"/docs/guinea-pigs/getting-started/guineapigcare"},{"id":"guinea-pigs/health-and-wellness/guineapigpoop","title":"Guinea Pig Poop","description":"Guinea pigs have sensitive digestive systems, and looking at their poop is the best way to quickly determine how your guinea pig\'s system is functioning. It\'s also one of the reasons why it\'s so...","permalink":"/docs/guinea-pigs/health-and-wellness/guineapigpoop"},{"id":"Chinchillas/illnesses-and-conditions/heartdisease","title":"Heart Disease and Heart Failure in Chinchillas","description":"Heart disease and heart failure are relatively uncommon in chinchillas but can still occur, especially as they age or due to certain genetic predispositions. These conditions can be challenging to detect early on, as chinchillas tend to hide their symptoms until the disease has progressed. Understanding the causes, signs, and treatments of heart disease in chinchillas is key to ensuring your pet remains healthy and receives proper care.","permalink":"/docs/Chinchillas/illnesses-and-conditions/heartdisease"},{"id":"Degus/health-and-wellness/home-health-care","title":"Home Health Care for Pet Degus","description":"A guide to performing regular at-home health checks for your pet degus to monitor their well-being and catch early signs of illness.","permalink":"/docs/Degus/health-and-wellness/home-health-care"},{"id":"Ferrets/health-and-wellness/home-health-care","title":"Home Health Care for Pet Ferrets","description":"A guide to performing regular at-home health checks for your pet ferrets to monitor their well-being and detect early signs of common illnesses.","permalink":"/docs/Ferrets/health-and-wellness/home-health-care"},{"id":"Gerbils/health-and-wellness/home-health-care","title":"Home Health Care for Pet Gerbils","description":"A guide to performing regular at-home health checks for your pet gerbils to monitor their well-being and catch early signs of illness.","permalink":"/docs/Gerbils/health-and-wellness/home-health-care"},{"id":"Hedgehogs/health-and-wellness/home-health-care","title":"Home Health Care for Pet Hedgehogs","description":"A guide to performing regular at-home health checks for your pet hedgehog to monitor their well-being and catch early signs of illness.","permalink":"/docs/Hedgehogs/health-and-wellness/home-health-care"},{"id":"guinea-pigs/breeds-and-genetics/know-your-guinea-pig-breeds","title":"Know Your Guinea Pig Breeds","description":"From the sleek and smooth to the curly and long-haired, guinea pigs come in a wonderful variety of breeds, each with its own unique look and grooming needs. While personality is individual, some...","permalink":"/docs/guinea-pigs/breeds-and-genetics/know-your-guinea-pig-breeds"},{"id":"Hamsters/breeds-and-genetics/know-your-hamster-breeds","title":"Know Your Hamster Breeds","description":"An overview of the five hamster species commonly kept as pets, with their key traits, size, and care considerations.","permalink":"/docs/Hamsters/breeds-and-genetics/know-your-hamster-breeds"},{"id":"Rabbits/illnesses-and-conditions/maxfactor","title":"Max Factor Rabbits","description":"Max Factor rabbits are a rare and unique type of rabbit affected by a genetic mutation that results in unusual physical characteristics. These rabbits have striking appearances due to differences in their fur and limbs. It\u2019s said that the condition is named after a rabbit named Max who was known to have the condition, but not much is known about the defect or its origin. However, the mutation also affects their health and mobility, creating both challenges and specific care needs. Here\u2019s everything you need to know about Max Factor rabbits, from their characteristics to the ethics of breeding them.","permalink":"/docs/Rabbits/illnesses-and-conditions/maxfactor"},{"id":"guinea-pigs/getting-started/nutrition-information","title":"Nutrition Information for Guinea Pigs","description":"A balanced and appropriate diet is the single most important factor in maintaining the health and well-being of your guinea pig. Unlike many other small pets, guinea pigs have specific and unique...","permalink":"/docs/guinea-pigs/getting-started/nutrition-information"},{"id":"guinea-pigs/getting-started/proper-handling-of-guinea-pigs","title":"Proper Handling of Guinea Pigs","description":"Proper handling is fundamental to building a trusting relationship with your guinea pig and ensuring their safety. As prey animals, guinea pigs can be naturally skittish and may be frightened by...","permalink":"/docs/guinea-pigs/getting-started/proper-handling-of-guinea-pigs"},{"id":"Chinchillas/getting-started/proper-handling","title":"Proper Handling of Pet Chinchillas","description":"A guide to safely and confidently handling pet chinchillas, with techniques for building trust and correctly picking them up.","permalink":"/docs/Chinchillas/getting-started/proper-handling"},{"id":"Ferrets/getting-started/proper-handling","title":"Proper Handling of Pet Ferrets","description":"A guide to the correct and safe methods for handling pet ferrets, including how to pick them up and the use of scruffing for training and procedures.","permalink":"/docs/Ferrets/getting-started/proper-handling"},{"id":"Hamsters/getting-started/proper-handling","title":"Proper Handling of Pet Hamsters","description":"A step-by-step guide to taming and safely handling your pet hamster, building a bond of trust through patience and positive reinforcement.","permalink":"/docs/Hamsters/getting-started/proper-handling"},{"id":"Hedgehogs/getting-started/proper-handling","title":"Proper Handling of Pet Hedgehogs","description":"A guide to safely and confidently handling a pet hedgehog, with tips for building trust and getting past their spiky defenses.","permalink":"/docs/Hedgehogs/getting-started/proper-handling"},{"id":"Mice/getting-started/proper-handling","title":"Proper Handling of Pet Mice","description":"Learn the best methods for safely handling your pet mice, building trust, and creating a positive bond through gentle and patient interaction.","permalink":"/docs/Mice/getting-started/proper-handling"},{"id":"Rabbits/getting-started/proper-handling","title":"Proper Handling of Pet Rabbits","description":"A guide to the correct and safe methods for handling a pet rabbit, focusing on building trust and preventing injury.","permalink":"/docs/Rabbits/getting-started/proper-handling"},{"id":"Rats/getting-started/proper-handling","title":"Proper Handling of Pet Rats","description":"Learn the best techniques for safely and confidently handling your pet rats, building a strong bond based on trust and positive reinforcement.","permalink":"/docs/Rats/getting-started/proper-handling"},{"id":"Rats/health-and-wellness/rat-dental-care","title":"Rat Dental Care Guide","description":"Dental health is one of the most important \u2014 and most overlooked \u2014 aspects of rat care. Because rat incisors grow continuously throughout life, they must wear down properly to prevent serious complications. A rat with dental problems will struggle to eat, lose weight rapidly, and can deteriorate quickly. Understanding how rat teeth work and how to support healthy dental wear is essential for every rat owner.","permalink":"/docs/Rats/health-and-wellness/rat-dental-care"},{"id":"Rats/breeds-and-genetics/rat-sexing-guide","title":"Rat Sexing Guide: How to Identify Male and Female Rats at Different Ages","description":"Correctly sexing rats is essential to prevent accidental litters and ensure proper housing. Rats can reproduce very young, and misidentification is one of the most common causes of surprise...","permalink":"/docs/Rats/breeds-and-genetics/rat-sexing-guide"},{"id":"Rats/getting-started/rat-treat-guide","title":"Rat Treat Guide","description":"This guide is meant to help you quickly check whether a food is generally safe as a treat for your rats. Research on rat nutrition is limited, so some guidance is based on related species or...","permalink":"/docs/Rats/getting-started/rat-treat-guide"},{"id":"guinea-pigs/illnesses-and-conditions/satinsyndrome","title":"Satin Syndrome in Guinea Pigs","description":"\u2705 Download our checklist here and bring it to your vet! \u2705","permalink":"/docs/guinea-pigs/illnesses-and-conditions/satinsyndrome"},{"id":"guinea-pigs/breeds-and-genetics/sexing-guinea-pigs","title":"Sexing Guinea Pigs","description":"Correctly identifying the sex of a guinea pig is a crucial skill for any owner, breeder, or rescue. It is the only way to prevent accidental and unwanted pregnancies, which can be dangerous for...","permalink":"/docs/guinea-pigs/breeds-and-genetics/sexing-guinea-pigs"},{"id":"guinea-pigs/getting-started/the-ideal-guinea-pig-habitat","title":"The Ideal Guinea Pig Habitat","description":"Creating a safe, spacious, and enriching environment is one of the most important responsibilities of a guinea pig owner. The right habitat directly impacts their physical health and mental...","permalink":"/docs/guinea-pigs/getting-started/the-ideal-guinea-pig-habitat"},{"id":"guinea-pigs/illnesses-and-conditions/clubbed-feet","title":"Understanding Clubbed Feet and Limb Deformities in Guinea Pigs","description":"Guinea pigs are known for their sweet personalities and unique charm\u2014but some arrive into rescue with visible physical challenges, including limb deformities commonly referred to as \\"clubbed feet.\\" Understanding this condition is key to providing these special-needs pigs with the quality of life they deserve.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/clubbed-feet"},{"id":"guinea-pigs/breeds-and-genetics/lethalwhite","title":"Understanding Lethal White Guinea Pigs","description":"Guinea pigs are beloved companions known for their sweet nature, vocal personalities, and varied appearances. But within the world of guinea pig care, there\u2019s a little-known and serious condition that deserves more awareness\u2014lethal white syndrome.","permalink":"/docs/guinea-pigs/breeds-and-genetics/lethalwhite"},{"id":"Rats/health-and-wellness/understanding-rat-behavior","title":"Understanding Rat Behavior: A Guide for Owners","description":"Rats are intelligent, social, and emotionally complex animals. Understanding their natural behaviors and unique ways of communicating is key to building a strong bond and providing them with the best...","permalink":"/docs/Rats/health-and-wellness/understanding-rat-behavior"},{"id":"guinea-pigs/breeds-and-genetics/hairless-skinny-pigs","title":"What to Know about Hairless or \\"Skinny\\" Pigs","description":"Hairless guinea pigs, most commonly known as \\"Skinny Pigs,\\" are a unique and increasingly popular variety of cavy. Their striking appearance, lacking the typical fluffy coat, makes them stand out, but it also means they have specialized care requirements that potential owners must be prepared to meet. Understanding their unique needs is essential to providing them with a healthy and happy life.","permalink":"/docs/guinea-pigs/breeds-and-genetics/hairless-skinny-pigs"}],"unlisted":false}}')}}]);